// Build 30-day baseline per resource_type + source
// Then identify new alerts (last 15 min) that deviate from baseline

const all = $input.all().map(i => i.json);
const now = new Date();
const fifteenMinAgo = new Date(now.getTime() - 15 * 60 * 1000);
const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

// Severity numeric weights
const sevWeight = { critical: 4, high: 3, medium: 2, low: 1, info: 0 };

// Baseline window: 2 days ago to 15 min ago (exclude the current window)
const twoHoursAgo = new Date(now.getTime() - 2 * 60 * 60 * 1000);
const baselineAlerts = all.filter(a => {
  const t = new Date(a.ingested_at);
  return t >= thirtyDaysAgo && t < twoHoursAgo;
});

// New alerts: last 15 minutes, not yet anomaly-checked
const newAlerts = all.filter(a => {
  const t = new Date(a.ingested_at);
  return t >= fifteenMinAgo && !a.anomaly_checked;
});

if (newAlerts.length === 0) {
  return [{ json: { _skip: true, reason: 'No new alerts in last 15 minutes' } }];
}

// Build baseline stats per (resource_type, source) group
const baseline = {};
baselineAlerts.forEach(a => {
  const key = `${a.resource_type}__${a.source}`;
  if (!baseline[key]) baseline[key] = { counts: [], severities: [], total: 0 };
  baseline[key].total++;
  baseline[key].severities.push(sevWeight[a.severity] || 1);
});

// Compute per-group: avg hourly rate + avg severity
const baselineHours = 30 * 24;
Object.keys(baseline).forEach(key => {
  const b = baseline[key];
  b.avg_hourly_rate = b.total / baselineHours;
  b.avg_severity = b.severities.reduce((a, c) => a + c, 0) / (b.severities.length || 1);
});

// Score each new alert against baseline
const results = newAlerts.map(alert => {
  const key = `${alert.resource_type}__${alert.source}`;
  const b = baseline[key];
  const currentSevWeight = sevWeight[alert.severity] || 1;

  let anomaly_score = 0;
  let anomaly_reasons = [];

  if (!b || b.total < 5) {
    // Not enough history — flag as unknown baseline
    anomaly_score = 5;
    anomaly_reasons.push('Insufficient baseline history for this resource type + source combination');
  } else {
    // Severity spike: current severity much higher than baseline avg
    const sevDelta = currentSevWeight - b.avg_severity;
    if (sevDelta >= 2) {
      anomaly_score += 4;
      anomaly_reasons.push(`Severity spike: ${alert.severity} vs baseline avg ${b.avg_severity.toFixed(1)}`);
    } else if (sevDelta >= 1) {
      anomaly_score += 2;
      anomaly_reasons.push(`Elevated severity vs baseline`);
    }

    // Count recent alerts for same resource_id in last 2 hours
    const recentSameResource = all.filter(a => {
      const t = new Date(a.ingested_at);
      return a.resource_id === alert.resource_id && t >= twoHoursAgo;
    }).length;

    if (recentSameResource >= 5) {
      anomaly_score += 5;
      anomaly_reasons.push(`Frequency spike: ${recentSameResource} alerts on same resource in 2 hours`);
    } else if (recentSameResource >= 3) {
      anomaly_score += 2;
      anomaly_reasons.push(`Repeated alerts on same resource (${recentSameResource} in 2h)`);
    }

    // New source never seen before for this resource type
    if (b.total === 0) {
      anomaly_score += 3;
      anomaly_reasons.push('First alert ever from this source for this resource type');
    }
  }

  anomaly_score = Math.min(10, anomaly_score);

  return {
    ...alert,
    anomaly_score,
    anomaly_reasons: anomaly_reasons.join('; ') || 'Within normal baseline',
    is_anomaly: anomaly_score >= 5,
    anomaly_checked: true,
    baseline_avg_severity: b ? b.avg_severity.toFixed(2) : 'N/A',
    baseline_hourly_rate: b ? b.avg_hourly_rate.toFixed(4) : 'N/A'
  };
});

return results.map(r => ({ json: r }));

