parameters.jsCode:
const item = $input.first().json;
const prev = $('Anomaly Filter').first().json;

let llmResult = {};
try {
  const content = item.choices?.[0]?.message?.content || '{}';
  llmResult = JSON.parse(content.replace(/```json|```/g, '').trim());
} catch(e) {
  llmResult = { llm_anomaly_verdict: 'monitor', llm_anomaly_reasoning: 'Parse error — manual review needed.', recommended_action: 'watch' };
}

return [{ json: {
  ...prev,
  llm_anomaly_verdict:    llmResult.llm_anomaly_verdict || 'monitor',
  llm_anomaly_reasoning:  llmResult.llm_anomaly_reasoning || '',
  recommended_action:     llmResult.recommended_action || 'watch',
  anomaly_model:          'mistralai/mistral-7b-instruct:free'
}}];

